import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Domande Frequenti per Giocatori (FAQ)","description":"Domande frequenti riguardanti Fabric per giocatori e admin di server.","frontmatter":{"title":"Domande Frequenti per Giocatori (FAQ)","description":"Domande frequenti riguardanti Fabric per giocatori e admin di server.","files":[]},"headers":[],"relativePath":"it_it/1.21.8/players/faq.md","filePath":"versions/1.21.8/translated/it_it/players/faq.md","lastUpdated":1760721669000}`);var a={name:`it_it/1.21.8/players/faq.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Domande Frequenti per Giocatori (FAQ) <a class="header-anchor" href="#h1" aria-label="Permalink to “Domande Frequenti per Giocatori (FAQ)”">​</a></h1><p>Ci sono molte domande che vengono poste di frequente, quindi ne abbiamo compilato una lista qui.</p><h2 id="what-minecraft-versions-does-fabric-support" tabindex="-1">Quali Versioni di Minecraft Supporta Fabric? <a class="header-anchor" href="#what-minecraft-versions-does-fabric-support" aria-label="Permalink to “Quali Versioni di Minecraft Supporta Fabric?”">​</a></h2><p>Ufficialmente, Fabric supporta tutte le versioni di Minecraft a partire da snapshot <code>18w43b</code> e seguenti, e dalla release <code>1.14</code> e superiori.</p><h2 id="where-can-i-download-published-fabric-mods" tabindex="-1">Dove Posso Scaricare le Mod Fabric Pubblicate? <a class="header-anchor" href="#where-can-i-download-published-fabric-mods" aria-label="Permalink to “Dove Posso Scaricare le Mod Fabric Pubblicate?”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Dovresti sempre controllare che le mod provengano da una fonte affidabile. Dai un occhiata alla guida <a href="./finding-mods">Trovare Mod Affidabili</a> per più informazioni.</p></div><p>La maggior parte degli autori pubblica le loro mod su <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> e CurseForge, anche se altri potrebbero aver deciso di caricarle sui loro siti personali o su altre piattaforme come le repository di GitHub.</p><h2 id="where-can-i-find-pre-made-fabric-modpacks" tabindex="-1">Dove Posso Trovare Modpack Fabric Prefabbricati? <a class="header-anchor" href="#where-can-i-find-pre-made-fabric-modpacks" aria-label="Permalink to “Dove Posso Trovare Modpack Fabric Prefabbricati?”">​</a></h2><p>Puoi trovare modpack Fabric prefabbricati su varie piattaforme, come:</p><ul><li><a href="https://modrinth.com/modpacks?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a></li><li><a href="https://www.curseforge.com/minecraft/search?class=modpacks&amp;gameVersionTypeId=4" target="_blank" rel="noreferrer">CurseForge</a></li><li><a href="https://www.feed-the-beast.com/ftb-app" target="_blank" rel="noreferrer">Feed The Beast</a></li><li><a href="https://www.technicpack.net/modpacks" target="_blank" rel="noreferrer">Technic</a></li></ul>`,10)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};